import type { EntityId } from "@/types/common";

const PDF_VIEWER_CHANNEL_PREFIX = "cotizacion-pdf-viewer";

type ViewerReadyMessage = {
  type: "viewer-ready";
};

type ViewerPayloadMessage = {
  type: "viewer-payload";
  fileName: string;
  blob: Blob;
};

type ViewerAckMessage = {
  type: "viewer-ack";
};

type ViewerBridgeMessage =
  | ViewerReadyMessage
  | ViewerPayloadMessage
  | ViewerAckMessage;

function sanitizeSlugPart(value: string) {
  return value
    .trim()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\.pdf$/i, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
}

export function createCotizacionPdfViewerBridgeId() {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }

  return `pdf-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
}

export function buildCotizacionPdfViewerUrl(cotizacionId: EntityId, fileName: string, bridgeId: string) {
  const slug = sanitizeSlugPart(fileName) || "cotizacion";
  return `/print/cotizaciones/${cotizacionId}/archivo/${slug}?bridge=${encodeURIComponent(bridgeId)}`;
}

export function getCotizacionPdfViewerChannelName(bridgeId: string) {
  return `${PDF_VIEWER_CHANNEL_PREFIX}:${bridgeId}`;
}

export function canUseCotizacionPdfViewerBridge() {
  return typeof BroadcastChannel !== "undefined";
}

export async function sendCotizacionPdfToViewer(input: {
  bridgeId: string;
  fileName: string;
  blob: Blob;
  timeoutMs?: number;
}) {
  if (!canUseCotizacionPdfViewerBridge()) {
    throw new Error("Este navegador no soporta el visor interno de PDF");
  }

  const channel = new BroadcastChannel(getCotizacionPdfViewerChannelName(input.bridgeId));
  const timeoutMs = input.timeoutMs ?? 8000;

  return new Promise<void>((resolve, reject) => {
    let settled = false;

    const cleanup = () => {
      channel.close();
      window.clearTimeout(timeoutId);
    };

    const settle = (fn: () => void) => {
      if (settled) {
        return;
      }

      settled = true;
      cleanup();
      fn();
    };

    const timeoutId = window.setTimeout(() => {
      settle(() => reject(new Error("El visor interno no respondio a tiempo")));
    }, timeoutMs);

    channel.onmessage = (event: MessageEvent<ViewerBridgeMessage>) => {
      if (event.data?.type === "viewer-ready") {
        channel.postMessage({
          type: "viewer-payload",
          fileName: input.fileName,
          blob: input.blob,
        } satisfies ViewerPayloadMessage);
        return;
      }

      if (event.data?.type === "viewer-ack") {
        settle(resolve);
      }
    };
  });
}

